1861:/// Fallback moment-based variance update (kept for ML estimation)
1862:fn update_variance_components_moment_based(
1863:    x: &ArrayView2<f64>,
1864:    z: &CsMat<f64>,
1865:    y: &ArrayView1<f64>,
1866:    beta: &Array1<f64>,
1867:    u: &Array1<f64>,
1868:    current_variances: &Array1<f64>,
1869:    use_reml: bool,
1870:    min_variance: f64,
1871:    step_damping: f64,
1872:) -> Result<Array1<f64>, OptimError> {
1873:    let n_obs = y.len();
1874:    let n_random = u.len();
1875:    
1876:    // Calculate residuals: e = y - Xβ - Zu
1877:    let fitted_fixed = x.dot(beta);
1878:    let fitted_random = sparse_matrix_vector_multiply(z, u);
1879:    let residuals = y - &fitted_fixed - &fitted_random;
1880:    
1881:    // Estimate residual variance: σ²_e = ||e||²/(n - p) for REML or ||e||²/n for ML
1882:    let residual_sum_sq = residuals.mapv(|r| r * r).sum();
1883:    let df_residual = if use_reml {
1884:        n_obs - x.ncols() // REML adjustment
1885:    } else {
1886:        n_obs // ML
1887:    };
1888:    
1889:    let new_sigma2_e = (residual_sum_sq / df_residual as f64).max(min_variance);
1890:    
1891:    // Estimate random effects variance: σ²_u = ||u||²/q
1892:    let random_sum_sq = u.mapv(|u_val| u_val * u_val).sum();
1893:    let new_sigma2_u = (random_sum_sq / n_random as f64).max(min_variance);
1894:    
1895:    // Apply step damping to prevent oscillation
1896:    let damped_sigma2_u = current_variances[0] + step_damping * (new_sigma2_u - current_variances[0]);
1897:    let damped_sigma2_e = current_variances[1] + step_damping * (new_sigma2_e - current_variances[1]);
1898:    
1899:    Ok(Array1::from(vec![
1900:        damped_sigma2_u.max(min_variance),
1901:        damped_sigma2_e.max(min_variance),
1902:    ]))
1903:}
