1984:    
1985:    // A' has dimensions (n_cols_a × n_rows_a)
1986:    // B has dimensions (n_rows_a × n_cols_b)
1987:    // Result has dimensions (n_cols_a × n_cols_b)
1988:    
1989:    for (i, row) in a.outer_iterator().enumerate() {
1990:        for (col_idx, &val) in row.iter() {
1991:            for j in 0..n_cols_b {
1992:                result[[col_idx, j]] += val * b[[i, j]];
