1816:            let mut theta_plus = theta.clone();
1817:            let mut theta_minus = theta.clone();
1818:            theta_plus[i] += h;
1819:            theta_minus[i] -= h;
1820:            grad[i] = (objective(&theta_plus) - objective(&theta_minus)) / (2.0 * h);
1821:        }
1822:        grad
1823:    };
1824:    
1825:    // Use L-BFGS-B to optimize with bounded parameters to ensure positive variances
1826:    let optim_config = LbfgsbConfig {
1827:        max_iter: 20,
1828:        tolerance: 1e-8,
1829:        // Bound log(sigma) to reasonable range: exp(-10) to exp(10)
1830:        lower_bounds: Some(Array1::from(vec![-10.0, -10.0])),
1831:        upper_bounds: Some(Array1::from(vec![10.0, 10.0])),
1832:        ..Default::default()
1833:    };
1834:    
1835:    eprintln!("DEBUG: Starting REML optimization from theta = {:?}", theta_start);
1836:    
1837:    let result = match lbfgsb(objective, gradient, theta_start, Some(optim_config)) {
1838:        Ok(res) => {
1839:            eprintln!("DEBUG: REML optimization converged to theta = {:?}", res.params);
1840:            res
1841:        },
1842:        Err(e) => {
1843:            eprintln!("DEBUG: REML optimization failed: {:?}", e);
1844:            // If optimization fails, fall back to moment-based estimates
1845:            return update_variance_components_moment_based(
1846:                x, z, y, beta, u, current_variances, use_reml, min_variance, step_damping
1847:            );
1848:        }
1849:    };
1850:    
1851:    // Transform back to variance scale
1852:    let sigma_u = result.params[0].exp();
1853:    let sigma_e = result.params[1].exp();
1854:    
1855:    Ok(Array1::from(vec![
1856:        (sigma_u * sigma_u).max(min_variance),
1857:        (sigma_e * sigma_e).max(min_variance),
1858:    ]))
1859:}
