1905:/// Calculate ML log-likelihood for mixed model
1906:fn calculate_ml_log_likelihood(
1907:    x: &ArrayView2<f64>,
1908:    z: &CsMat<f64>,
1909:    y: &ArrayView1<f64>,
1910:    beta: &Array1<f64>,
1911:    u: &Array1<f64>,
1912:    variances: &Array1<f64>,
1913:) -> Result<f64, OptimError> {
1914:    let n_obs = y.len() as f64;
1915:    let sigma2_u = variances[0];
1916:    let sigma2_e = variances[1];
1917:    
1918:    // Calculate fitted values and residuals
1919:    let fitted_fixed = x.dot(beta);
1920:    let fitted_random = sparse_matrix_vector_multiply(z, u);
1921:    let residuals = y - &fitted_fixed - &fitted_random;
1922:    
1923:    // Log-likelihood components
1924:    let residual_ss = residuals.mapv(|r| r * r).sum();
1925:    let random_penalty = u.mapv(|u_val| u_val * u_val).sum() / sigma2_u;
1926:    
1927:    // ML log-likelihood (simplified, ignoring constant terms)
1928:    let log_likelihood = -0.5 * (
1929:        n_obs * (2.0 * std::f64::consts::PI * sigma2_e).ln()
1930:        + residual_ss / sigma2_e
1931:        + random_penalty
1932:    );
1933:    
1934:    Ok(log_likelihood)
1935:}
