1937:/// Calculate REML log-likelihood for mixed model
1938:fn calculate_reml_log_likelihood(
1939:    x: &ArrayView2<f64>,
1940:    z: &CsMat<f64>,
1941:    y: &ArrayView1<f64>,
1942:    beta: &Array1<f64>,
1943:    u: &Array1<f64>,
1944:    variances: &Array1<f64>,
1945:) -> Result<f64, OptimError> {
1946:    // For REML, we need to account for the fixed effects estimation uncertainty
1947:    // This is a simplified version - full REML would include log|X'V⁻¹X| term
1948:    let ml_loglik = calculate_ml_log_likelihood(x, z, y, beta, u, variances)?;
1949:    
1950:    // REML adjustment (simplified)
1951:    let _n_obs = y.len() as f64;
1952:    let n_fixed = x.ncols() as f64;
1953:    let reml_adjustment = -0.5 * n_fixed * (2.0 * std::f64::consts::PI).ln();
1954:    
1955:    Ok(ml_loglik + reml_adjustment)
1956:}
