1958:/// Efficient sparse matrix multiplication: A'A where A is sparse
1959:fn sparse_matrix_multiply_ata(a: &CsMat<f64>) -> Array2<f64> {
1960:    let n_cols = a.cols();
1961:    let mut result = Array2::zeros((n_cols, n_cols));
1962:    
1963:    // Iterate over rows of A and accumulate products
1964:    for (_row_idx, row) in a.outer_iterator().enumerate() {
1965:        // For each row, compute the outer product of its non-zero elements
1966:        // and add to the result matrix
1967:        for (col_i, &val_i) in row.iter() {
1968:            for (col_j, &val_j) in row.iter() {
1969:                result[[col_i, col_j]] += val_i * val_j;
1970:            }
1971:        }
1972:    }
1973:    
1974:    result
1975:}
