1977:/// Efficient sparse matrix multiplication: A'B where A is sparse, B is dense
1978:fn sparse_matrix_multiply_atb(a: &CsMat<f64>, b: &ArrayView2<f64>) -> Array2<f64> {
1979:    let _n_rows_a = a.rows();
1980:    let n_cols_a = a.cols();
1981:    let n_cols_b = b.ncols();
1982:    
1983:    let mut result = Array2::zeros((n_cols_a, n_cols_b));
1984:    
1985:    // A' has dimensions (n_cols_a × n_rows_a)
1986:    // B has dimensions (n_rows_a × n_cols_b)
1987:    // Result has dimensions (n_cols_a × n_cols_b)
1988:    
1989:    for (i, row) in a.outer_iterator().enumerate() {
1990:        for (col_idx, &val) in row.iter() {
1991:            for j in 0..n_cols_b {
1992:                result[[col_idx, j]] += val * b[[i, j]];
1993:            }
1994:        }
1995:    }
1996:    
1997:    result
1998:}
1999:
2000:/// Efficient sparse matrix-vector multiplication: A'v where A is sparse
2001:fn sparse_matrix_vector_multiply_at(a: &CsMat<f64>, v: &ArrayView1<f64>) -> Array1<f64> {
2002:    let n_cols = a.cols();
2003:    let mut result = Array1::zeros(n_cols);
2004:    
2005:    for (i, row) in a.outer_iterator().enumerate() {
2006:        for (col_idx, &val) in row.iter() {
2007:            result[col_idx] += val * v[i];
2008:        }
2009:    }
2010:    
2011:    result
2012:}
