2014:/// Efficient sparse matrix-vector multiplication: Av where A is sparse
2015:fn sparse_matrix_vector_multiply(a: &CsMat<f64>, v: &Array1<f64>) -> Array1<f64> {
2016:    let n_rows = a.rows();
2017:    let mut result = Array1::zeros(n_rows);
2018:    
2019:    for (i, row) in a.outer_iterator().enumerate() {
2020:        for (col_idx, &val) in row.iter() {
2021:            result[i] += val * v[col_idx];
2022:        }
2023:    }
2024:    
2025:    result
2026:}
