2028:/// Matrix inversion using faer
2029:fn matrix_inverse(a: &Array2<f64>) -> Result<Array2<f64>, OptimError> {
2030:    let (n_rows, n_cols) = a.dim();
2031:    if n_rows != n_cols {
2032:        return Err(OptimError::Numerical(
2033:            "Matrix must be square for inversion".to_string(),
2034:        ));
2035:    }
2036:    
2037:    // Convert to faer
2038:    let a_faer = Mat::from_fn(n_rows, n_cols, |i, j| a[[i, j]]);
2039:    
2040:    // Compute inverse using LU decomposition
2041:    let lu = a_faer.partial_piv_lu();
2042:    let inv_faer = lu.solve(Mat::identity(n_rows, n_cols));
2043:    
2044:    // Convert back to ndarray
2045:    let mut inv = Array2::zeros((n_rows, n_cols));
2046:    for i in 0..n_rows {
2047:        for j in 0..n_cols {
2048:            inv[[i, j]] = inv_faer[(i, j)];
2049:        }
2050:    }
2051:    
2052:    Ok(inv)
2053:}
